//   text: 'Название дороги'
// }, {
//   dataField: 'number_road',
//   text: 'Номер дороги'
// }];


function Sing() {
    const [{ data, loading, error }, refetch] = useAxios('http://127.0.0.1:5000/sings');

    if (loading) {
        return(
            <div className='loading'>
                <p>Загрузка данных...</p>
            </div>
        );
    }

    if (error) {
        return(
            <div className='error'>
                <p>Ошибка:</p>
                <p>{error.message}</p>
                <button onClick={() => refetch()}>
                    Повторный запрос
                </button>
            </div>
        );
    }

    return (
        <div>
            <button onClick={refetch}>refetch</button>
            <pre>{JSON.stringify(data, null, 2)}</pre>
        </div>
    )

    // let list_sings = []
